openscad:
watch_diameter = 40; // [30:1:60]
case_height = 8; // [4:1:15]
dial_thickness = 2; // [1:0.5:4]
hand_width = 1.5; // [0.5:0.5:3]
hour_hand_length = 15; // [8:1:25]
minute_hand_length = 20; // [10:1:30]
second_hand_length = 25; // [12:1:35]
bezel_thickness = 3; // [1:0.5:6]
$fn = 60;

module watch_case() {
    difference() {
        cylinder(d=watch_diameter+bezel_thickness*2, h=case_height);
        translate([0,0,case_height-dial_thickness])
            cylinder(d=watch_diameter, h=dial_thickness+0.1);
        translate([0,0,-0.1])
            cylinder(d=watch_diameter-4, h=case_height);
    }
}

module dial() {
    color("black")
    cylinder(d=watch_diameter-2, h=dial_thickness);
}

module hand(length, w) {
    color("white")
    translate([0,0,dial_thickness+0.1])
        linear_extrude(height=1.5)
            polygon(points=[
                [-w/2,0],
                [w/2,0],
                [w/4,length],
                [-w/4,length]
            ]);
}

module watch() {
    watch_case();
    dial();
    // hour hand (15mm at ~3 o'clock)
    rotate([0,0,90])
        hand(hour_hand_length, hand_width);
    // minute hand (20mm at 12 o'clock)
    hand(minute_hand_length, hand_width*0.8);
    // second hand (25mm at 6 o'clock)
    rotate([0,0,180])
        hand(second_hand_length, hand_width*0.6);
}

watch();
